function checkTemperature(env) {
  if (env.temperature > env.threshold) {
    return { warning: true, message: `温度 ${env.temperature} 超过阈值 ${env.threshold}` };
  }
  return { warning: false };
}

function allocateResources(resources, weights) {
  const total = weights.reduce((sum, w) => sum + w, 0);
  if (total === 0) return new Array(weights.length).fill(0);

  return weights.map(w => (resources * w / total).toFixed(2));
}

function calculateYield(crop, area, rainfall, temperature) {
  const baseYield = crop.baseYield;
  const rainFactor = rainfall < crop.minRain ? 0.7 : rainfall > crop.maxRain ? 0.8 : 1.0;
  const tempFactor = temperature < crop.minTemp ? 0.8 : temperature > crop.maxTemp ? 0.7 : 1.0;

  return baseYield * area * rainFactor * tempFactor;
}

function calculatePortfolioRisk(investments, market_volatility) {
  let totalRisk = 0;
  let totalWeight = 0;

  for (const inv of investments) {
    totalRisk += inv.risk * inv.weight;
    totalWeight += inv.weight;
  }

  const avgRisk = totalWeight > 0 ? totalRisk / totalWeight : 0;
  const finalRisk = avgRisk * market_volatility;

  return {
    risk_level: finalRisk,
    risk_category: finalRisk < 0.3 ? 'low' : finalRisk < 0.7 ? 'medium' : 'high'
  };
}

function scoreArchitecture(architecture, requirements) {
  const scores = {
    scalability: 0,
    reliability: 0,
    maintainability: 0,
    performance: 0,
    security: 0
  };

  // 评分逻辑
  if (architecture.includes('microservices')) {
    scores.scalability += 8;
    scores.maintainability += 7;
    scores.reliability += 6;
    scores.performance -= 2;
  }

  if (architecture.includes('kubernetes')) {
    scores.scalability += 9;
    scores.reliability += 8;
  }

  if (architecture.includes('monolith')) {
    scores.maintainability += 4;
    scores.performance += 7;
    scores.scalability -= 3;
  }

  if (architecture.includes('serverless')) {
    scores.scalability += 9;
    scores.maintainability += 6;
    scores.performance += 5;
  }

  // 安全评分
  if (architecture.includes('encryption')) scores.security += 7;
  if (architecture.includes('firewall')) scores.security += 6;
  if (architecture.includes('auth')) scores.security += 8;

  // 根据需求调整权重
  let totalScore = 0;
  let maxScore = 0;

  for (const req of requirements) {
    totalScore += scores[req.category] * req.weight;
    maxScore += 10 * req.weight; // 假设每项满分为10
  }

  return {
    total_score: totalScore,
    percentage: Math.round((totalScore / maxScore) * 100),
    breakdown: scores
  };
}

function assessLearningProgress(answers, target_concepts) {
  const scores = {};
  let totalScore = 0;

  for (const concept of target_concepts) {
    // 检查学生回答中是否有关键概念
    const relevantAnswers = answers.filter(a => a.concept === concept.name);
    if (relevantAnswers.length === 0) {
      scores[concept.name] = 0;
      continue;
    }

    // 计算该概念的得分
    const answer = relevantAnswers[0];
    let conceptScore = 0;

    if (answer.correct) {
      conceptScore += 7;
    }

    if (answer.explanation && answer.explanation.length > 0) {
      conceptScore += Math.min(3, answer.explanation.length / 20);
    }

    scores[concept.name] = Math.min(10, conceptScore);
    totalScore += scores[concept.name] * concept.weight;
  }

  const totalWeight = target_concepts.reduce((sum, c) => sum + c.weight, 0);
  const averageScore = totalWeight > 0 ? totalScore / totalWeight : 0;

  return {
    average_score: Math.round(averageScore * 10) / 10,
    mastery_level: averageScore < 4 ? 'beginning' : averageScore < 7 ? 'developing' : averageScore < 9 ? 'proficient' : 'advanced',
    concept_scores: scores
  };
}

function assessBattlefieldSituation(forces, terrain, weather, intelligence) {
  // 计算双方战斗力评分
  const calculateCombatPower = (force) => {
    let power = 0;
    // 基础战斗力
    power += force.personnel * 1;
    power += force.armor * 10;
    power += force.artillery * 8;
    power += force.air_support * 15;

    // 地形影响
    const terrainFactor = {
      'urban': { infantry: 1.2, armor: 0.7, artillery: 0.9 },
      'forest': { infantry: 1.1, armor: 0.6, artillery: 0.8 },
      'desert': { infantry: 0.9, armor: 1.3, artillery: 1.1 },
      'mountain': { infantry: 1.3, armor: 0.5, artillery: 0.7 },
      'plain': { infantry: 1.0, armor: 1.2, artillery: 1.2 }
    };

    // 应用地形因素
    if (terrain in terrainFactor) {
      power = power * (
        (force.personnel * terrainFactor[terrain].infantry +
         force.armor * terrainFactor[terrain].armor +
         force.artillery * terrainFactor[terrain].artillery) /
        (force.personnel + force.armor + force.artillery)
      );
    }

    // 天气影响
    const weatherFactor = {
      'clear': 1.0,
      'rain': 0.9,
      'snow': 0.7,
      'fog': 0.8,
      'storm': 0.6
    };

    if (weather in weatherFactor) {
      power = power * weatherFactor[weather];
    }

    // 情报优势
    power = power * (1 + (force.intelligence_advantage || 0));

    // 士气影响
    power = power * (force.morale || 1.0);

    return power;
  };

  const friendlyPower = calculateCombatPower(forces.friendly);
  const enemyPower = calculateCombatPower(forces.enemy);

  // 计算相对优势
  const powerRatio = friendlyPower / enemyPower;

  // 评估态势
  let situation;
  if (powerRatio > 3.0) {
    situation = 'overwhelming_advantage';
  } else if (powerRatio > 1.5) {
    situation = 'significant_advantage';
  } else if (powerRatio > 1.1) {
    situation = 'slight_advantage';
  } else if (powerRatio > 0.9) {
    situation = 'even';
  } else if (powerRatio > 0.6) {
    situation = 'slight_disadvantage';
  } else if (powerRatio > 0.3) {
    situation = 'significant_disadvantage';
  } else {
    situation = 'critical_disadvantage';
  }

  // 情报可靠性评估
  const intelReliability = intelligence.reliability || 0.7;

  return {
    friendly_power: Math.round(friendlyPower),
    enemy_power: Math.round(enemyPower),
    power_ratio: Math.round(powerRatio * 100) / 100,
    situation: situation,
    confidence: Math.round(intelReliability * 100),
    recommended_posture: powerRatio > 1.2 ? 'offensive' : powerRatio < 0.8 ? 'defensive' : 'balanced'
  };
}
